/**
 * @summary List VeriFactu records
 */
export const getListVeriFactuRecordsUrl = (
  taxpayerId: number,
  params?: ListVeriFactuRecordsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/taxpayers/${taxpayerId}/verifactu/records?${stringifiedParams}`
    : `/api/taxpayers/${taxpayerId}/verifactu/records`;
};

